INSERT INTO recetas (id, nombre, descripcion, tiempo_preparacion) VALUES (1, 'Pad Thai de Pollo', 'Fideos de arroz salteados con pollo, huevo, brotes y cacahuetes.', '25 min'), (2, 'Lasaña Boloñesa Clásica', 'Capas de pasta con salsa de carne, bechamel casera y queso derretido.', '60 min'), (3, 'Risotto de Setas salvajes', 'Arroz cremoso italiano cocinado a fuego lento con variedad de setas.', '35 min'), (4, 'Hamburguesa Gourmet', 'Medallón de ternera con queso, lechuga y salsa especial en pan tierno.', '15 min'), (5, 'Hummus de Garbanzo Casero', 'Crema suave de garbanzos, tahini, limón, aceite de oliva y un toque de comino.', '10 min'), (6, 'Tacos de Salmón y Aguacate', 'Tortillas de maíz rellenas de salmón a la plancha, aguacate y cilantro.', '20 min'), (7, 'Wok de Langostinos', 'Salteado rápido de langostinos con verduras frescas y salsa de soja.', '15 min'), (8, 'Tortilla de Patatas Tradicional', 'La receta clásica española con huevos camperos, patatas y cebolla.', '30 min'), (9, 'Crema de Calabaza y Queso', 'Puré fino de calabaza asada con un toque de queso crema suave.', '25 min'), (10, 'Bowl de Arroz y Pollo Teriyaki', 'Base de arroz con pollo caramelizado en salsa teriyaki casera.', '25 min');
